  const gap = opts.gap ?? 12;
  const background = opts.background ?? { r: 255, g: 255, b: 255, alpha: 1 };
  const cols = Math.ceil(Math.sqrt(inputPaths.length));
  const rows = Math.ceil(inputPaths.length / cols);
