var PROVIDER_GUIDANCE = {
  google: "Gemini image models prefer concise but vivid prose: subject + setting + style + lighting + camera. Avoid bullet lists.",
  openai: "gpt-image-2 prefers direct, visual descriptions. Avoid abstract concepts. Specify orientation if relevant.",
  openrouter: "Routed via OpenRouter \u2014 the upstream model is usually Gemini-style. Concise, vivid, scene-first.",
  elevenlabs: "(no image rewrites for elevenlabs)",
  local: "Local server \u2014 keep it simple and direct. Local image models (Stable Diffusion variants) prefer subject + style + medium tags.",
  voicebox: "(no image rewrites for voicebox \u2014 TTS-only)"
};
var SamplingResultSchema = external_exports.object({
  role: external_exports.string().optional(),
  content: external_exports.union([
    external_exports.object({ type: external_exports.literal("text"), text: external_exports.string() }),
    external_exports.array(external_exports.object({ type: external_exports.string(), text: external_exports.string().optional() }).passthrough())
  ]).optional(),
  model: external_exports.string().optional(),
  stopReason: external_exports.string().optional()
});
async function rewritePromptViaMcpSampling(server2, prompt, providerId) {
  if (!prompt || prompt.trim().length === 0) return null;
  const guidance = PROVIDER_GUIDANCE[providerId];
  const system = `You rewrite prompts for AI image generation. Output ONLY the rewritten prompt \u2014 no preamble, no explanation, no quotes around it. Keep the user's subject and intent intact. Add concrete visual details (lighting, setting, mood, camera) where useful. Maximum 200 words.

Provider guidance: ${guidance}`;
  try {
    const raw = await server2.request(
      {
        method: "sampling/createMessage",
        params: {
          messages: [
            {
              role: "user",
              content: { type: "text", text: prompt }
            }
          ],
          systemPrompt: system,
          maxTokens: 400,
          temperature: 0.4
        }
      },
      SamplingResultSchema
    );
    const text = extractText(raw.content);
    if (!text) return null;
    const cleaned = text.trim().replace(/^["']|["']$/g, "");
    if (cleaned.length === 0 || cleaned.length > 4e3) return null;
    return { rewritten: cleaned, usedSampling: true };
  } catch {
    return null;
  }
}
function extractText(content) {
  if (!content) return null;
  if (typeof content === "object" && "text" in content) {
    const t2 = content.text;
    return typeof t2 === "string" ? t2 : null;
  }
  if (Array.isArray(content)) {
    for (const part of content) {
      if (part?.type === "text" && typeof part.text === "string") return part.text;
    }
  }
  return null;
}

